660	/// Constant-folding `luaK_posfix` for arithmetic binary operators where both
661	/// operands are already numeric literals (`KInt` / `KFlt`). Mirrors the
662	/// `constfolding` branch in C's `luaK_posfix`: when both operands are
663	/// numerals, the result is computed at compile time and stored back into
664	/// `e1`. Non-foldable arithmetic / bitwise binops fall through to the
665	/// two-register emit path (`OP_ADD` ... `OP_SHR`) plus an `OP_MMBIN`
666	/// metamethod-dispatch instruction. `Concat` is delegated to
667	/// `cg_emit_concat`; `Lt` to `cg_emit_order`; remaining logical and
668	/// comparison operators still hit `todo!()` so they surface as later
669	/// iterations' blockers.
670	fn cg_posfix_fold(
671	    fs: &mut FuncState,
672	    op: BinOpr,
673	    e1: &mut ExprDesc,
674	    e2: &mut ExprDesc,
675	    line: i32,
676	) -> Result<(), LuaError> {
677	    cg_discharge_vars(fs, line, e2)?;
678	
679	    let promote = |k: ExprKind, u: &ExprPayload| -> Option<f64> {
680	        match k {
681	            ExprKind::KInt => Some(u.ival as f64),
682	            ExprKind::KFlt => Some(u.nval),
683	            _ => None,
684	        }
685	    };
686	
687	    let foldable = e1.t == NO_JUMP && e1.f == NO_JUMP
688	        && e2.t == NO_JUMP && e2.f == NO_JUMP;
689	
690	    if foldable {
691	    if let (ExprKind::KInt, ExprKind::KInt) = (e1.k, e2.k) {
692	        let a = e1.u.ival;
693	        let b = e2.u.ival;
694	        let r: Option<i64> = match op {
695	            BinOpr::Add => Some(a.wrapping_add(b)),
696	            BinOpr::Sub => Some(a.wrapping_sub(b)),
697	            BinOpr::Mul => Some(a.wrapping_mul(b)),
698	            BinOpr::Mod if b != 0 => Some(a.rem_euclid(b)),
699	            BinOpr::IDiv if b != 0 => Some(a.div_euclid(b)),
700	            BinOpr::BAnd => Some(a & b),
701	            BinOpr::BOr  => Some(a | b),
702	            BinOpr::BXor => Some(a ^ b),
703	            _ => None,
704	        };
705	        if let Some(v) = r {
706	            e1.k = ExprKind::KInt;
707	            e1.u.ival = v;
708	            return Ok(());
709	        }
710	    }
711	    if let (Some(a), Some(b)) = (promote(e1.k, &e1.u), promote(e2.k, &e2.u)) {
712	        let r: Option<f64> = match op {
713	            BinOpr::Add => Some(a + b),
714	            BinOpr::Sub => Some(a - b),
715	            BinOpr::Mul => Some(a * b),
716	            BinOpr::Div => Some(a / b),
717	            BinOpr::Pow => Some(a.powf(b)),
718	            _ => None,
719	        };
720	        if let Some(v) = r {
721	            if v.is_finite() {
722	                e1.k = ExprKind::KFlt;
723	                e1.u.nval = v;
724	                return Ok(());
725	            }
726	        }
727	    }
728	    }
