819	    let is_le = matches!(op, BinOpr::Le);
820	    let (op_imm_e2, op_imm_e1, op_reg) = if is_le {
821	        (
822	            lua_code::opcodes::OpCode::LeI,
823	            lua_code::opcodes::OpCode::GeI,
824	            lua_code::opcodes::OpCode::Le,
825	        )
826	    } else {
827	        (
828	            lua_code::opcodes::OpCode::LtI,
829	            lua_code::opcodes::OpCode::GtI,
830	            lua_code::opcodes::OpCode::Lt,
831	        )
832	    };
833	    let (r1, r2, cmp_op) = if let Some(im) = cg_sc_int(e2) {
834	        let r1 = cg_exp_to_any_reg(fs, line, e1)?;
