                            |a, b| imod(a, b), fmodf)?;
                    }
                    // C: op_arithfK(L, luai_numpow) — float only
                    OpCode::PowK => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.proto_const(&cl, i.arg_c() as usize).clone();
