                    // C: Protect(luaV_objlen(L, ra, vRB(i)));
                    OpCode::Len => {
                        let ra = base + i.arg_a();
                        let rb_v = state.get_at(base + i.arg_b()).clone();
                        state.set_ci_savedpc(ci, pc);
                        state.set_top(state.ci_top(ci));
